import{_ as e,o as l,c as t,ak as r}from"./chunks/framework.B_unCYUt.js";const _=JSON.parse('{"title":"数据库系统原理","description":"","frontmatter":{},"headers":[],"relativePath":"数据库系统原理.md","filePath":"数据库系统原理.md","lastUpdated":1752476152000}'),i={name:"数据库系统原理.md"};function o(s,a,n,p,d,c){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="数据库系统原理" tabindex="-1">数据库系统原理 <a class="header-anchor" href="#数据库系统原理" aria-label="Permalink to “数据库系统原理”">​</a></h1><ul><li><a href="https://www.modb.pro/db/48999" target="_blank" rel="noreferrer">数据库类别</a><ul><li>关系型数据库 <ul><li>MySQL</li><li>PostgreSQL</li></ul></li><li>键值数据库 <ul><li>Redis</li></ul></li><li>文档型数据库 <ul><li>MongoDB</li></ul></li><li>检索型数据库 <ul><li>elasticsearch</li></ul></li><li>图数据库</li><li>时序数据库</li></ul></li></ul><p><a href="https://blog.bytebytego.com/i/127263496/a-handy-cheatsheet-for-sql-and-nosql-databases" target="_blank" rel="noreferrer">https://blog.bytebytego.com/i/127263496/a-handy-cheatsheet-for-sql-and-nosql-databases</a></p><p><img src="https://wwfyde.oss-cn-hangzhou.aliyuncs.com/images/202306161008344.jpeg" alt="graphical user interface, application, table"></p><h1 id="零散记录" tabindex="-1">零散记录 <a class="header-anchor" href="#零散记录" aria-label="Permalink to “零散记录”">​</a></h1><p>mysql数据库在系统上是以一个文件夹的形式出现的，你创建了ac数据库，那么在磁盘上就会出现ac的目录，而ac数据库的全局配置则是ac文件夹中的db.opt文件来管理。mysql的数据文件在datadir下，你在数据库中执行 show variables like &#39;%datadir%&#39;;就会显示数据库文件的路径，你可以找到ac文件夹。</p><p>文件和图片存储的方式</p><p>将文件存储到磁盘, 数据库中存取文件的路径</p><p>实体(entity)对应数据库中的表(table)</p><p>应用(app)对应数据库中的实例(instance)</p><p>实体属性(attribute)对应表格中的列(column)</p><p>关系则用相同的条件表示, 当实体间满足某个属性相同则存在关系</p><h1 id="基本概念" tabindex="-1">基本概念 <a class="header-anchor" href="#基本概念" aria-label="Permalink to “基本概念”">​</a></h1><h2 id="索引" tabindex="-1">索引 - <a class="header-anchor" href="#索引" aria-label="Permalink to “索引 -”">​</a></h2><p>一种数据结构, 索引文件</p><p>常见的索引结构有 B树, B+树, 哈希表</p><p>数据库以二维表的形式存储，如果我们以某一属性或多条属性为条件查找时，如果没进行查询优化，那么就只能从头开始顺序查找，效率极低。所以我们可以建立<code>索引</code>（是一种数据结构）`来帮我们快速定位（该数据结构的查询速率快于顺序查询）到某个地址来找到某一行，以此来优化查询。常见的索引结构有B树、B+树、哈希表。</p><p>我们知道数据表其实是存储在存储器中的，一般来说，索引本身也很大，不可能全部存储在内存中，因此<strong>索引往往以索引文件的形式存储的磁盘上</strong>。当我们要查询时就需要先去存储器中读取索引，通过索引去快速定位数据。这就意味着<code>索引查找过程中就要产生磁盘I/O消耗</code>。 相对于内存存取，I/O存取的消耗要高几个数量级，所以评价一个数据结构作为索引的优劣最重要的指标就是在查找过程中磁盘I/O操作次数的渐进复杂度。换句话说，<code>索引的结构组织要尽量减少查找过程中磁盘I/O的存取次数。</code>在这之前，我们要知道磁盘存取原理</p><p>记录</p><h1 id="数据库设计" tabindex="-1">数据库设计 <a class="header-anchor" href="#数据库设计" aria-label="Permalink to “数据库设计”">​</a></h1><h2 id="第一范式-1nf" tabindex="-1">第一范式(1NF) <a class="header-anchor" href="#第一范式-1nf" aria-label="Permalink to “第一范式(1NF)”">​</a></h2><p>first normal form</p>',22)])])}const b=e(i,[["render",o]]);export{_ as __pageData,b as default};
